const config = $input.item.json;
const baseUrl = $env.TULEAP_BASE_URL;
const accessKey = $env.TULEAP_ACCESS_KEY;
const trackerId = config.tuleap_tracker_id;
const qcProjectId = config.qc_project_id;
const trackerType = config.tracker_type;

const MAX_PAGES = 50;
const LIMIT = 100;

const present = [];
let offset = 0;
let pageCount = 0;
let truncated = false;

while (pageCount < MAX_PAGES) {
  const url = `${baseUrl}/api/v1/trackers/${trackerId}/artifacts?limit=${LIMIT}&offset=${offset}&values_format=collection`;
  let resp;
  try {
    resp = await this.helpers.httpRequest({
      url,
      method: 'GET',
      headers: { 'X-Auth-AccessKey': accessKey },
      json: true,
    });
  } catch (err) {
    return [{ json: { skipped: true, reason: `tuleap_fetch_failed: ${err.message}`, tuleap_tracker_id: trackerId } }];
  }
  const items = Array.isArray(resp) ? resp : (resp.collection || resp.data || []);
  if (!items.length) break;
  for (const a of items) present.push(a.id);
  pageCount += 1;
  if (items.length < LIMIT) break;
  offset += LIMIT;
}
if (pageCount >= MAX_PAGES) truncated = true;

try {
  const reconcileResp = await this.helpers.httpRequest({
    url: 'http://qc-api:3001/tuleap-webhook/reconcile-deletes',
    method: 'POST',
    body: {
      tuleap_tracker_id: trackerId,
      qc_project_id: qcProjectId,
      tracker_type: trackerType,
      present_artifact_ids: present,
      page_count: pageCount,
      truncated,
    },
    json: true,
  });
  return [{ json: { tuleap_tracker_id: trackerId, present_count: present.length, page_count: pageCount, truncated, qc_response: reconcileResp } }];
} catch (err) {
  return [{ json: { skipped: true, reason: `qc_post_failed: ${err.message}`, tuleap_tracker_id: trackerId, present_count: present.length } }];
}
